import React, { useState, useEffect, useRef } from 'react';
import { Users, ArrowUpDown, Play, RotateCcw, Search } from 'lucide-react';

interface Student {
    id: number;
    name: string;
    section: number;
    grade: number;
}

const INITIAL_STUDENTS: Student[] = [
    { id: 1, name: 'Alice', section: 2, grade: 85 },
    { id: 2, name: 'Bob', section: 1, grade: 92 },
    { id: 3, name: 'Charlie', section: 2, grade: 78 },
    { id: 4, name: 'Dave', section: 3, grade: 95 },
    { id: 5, name: 'Eve', section: 1, grade: 88 },
    { id: 6, name: 'Frank', section: 3, grade: 72 },
    { id: 7, name: 'Grace', section: 2, grade: 90 },
];

export const ComparatorVisualizer = ({ configStr }: { configStr: string }) => {
    const [students, setStudents] = useState<Student[]>([...INITIAL_STUDENTS]);
    const [sortBy, setSortBy] = useState<'name' | 'section' | 'grade'>('name');

    // Animation State
    const [activePair, setActivePair] = useState<[number, number] | null>(null); // Indices being compared
    const [isSorted, setIsSorted] = useState(false);
    const [isRunning, setIsRunning] = useState(false);
    const [compares, setCompares] = useState(0);
    const [logs, setLogs] = useState<string[]>([]);

    const stopRef = useRef(false);

    useEffect(() => {
        reset();
    }, []);

    const log = (msg: string) => setLogs(prev => [msg, ...prev].slice(0, 50));

    const reset = () => {
        stopRef.current = true;
        // Shuffle initial students for better demo
        const shuffled = [...INITIAL_STUDENTS].sort(() => Math.random() - 0.5);
        setStudents(shuffled);
        setActivePair(null);
        setIsSorted(false);
        setIsRunning(false);
        setCompares(0);
        setLogs(["Ready. Select a Comparator strategy."]);
        setTimeout(() => stopRef.current = false, 50);
    };

    const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

    // Comparators
    const comparators = {
        name: (a: Student, b: Student) => a.name.localeCompare(b.name),
        section: (a: Student, b: Student) => a.section - b.section,
        grade: (a: Student, b: Student) => b.grade - a.grade // Descending for grade
    };

    const runSort = async () => {
        if (isRunning) return;
        setIsRunning(true);
        stopRef.current = false;
        setCompares(0);

        log(`Sorting by ${sortBy.toUpperCase()}...`);

        // Use Insertion Sort for visual clarity (easy to see swaps)
        const arr = [...students];
        const n = arr.length;
        const compareFn = comparators[sortBy];

        for (let i = 1; i < n; i++) {
            for (let j = i; j > 0; j--) {
                if (stopRef.current) { setIsRunning(false); return; }

                setActivePair([j, j-1]);
                setCompares(c => c + 1);

                const valA = arr[j];
                const valB = arr[j-1];
                const cmp = compareFn(valA, valB);

                let desc = "";
                if (sortBy === 'name') desc = `Compare "${valA.name}" vs "${valB.name}"`;
                else if (sortBy === 'section') desc = `Compare Sec ${valA.section} vs Sec ${valB.section}`;
                else desc = `Compare Grade ${valA.grade} vs Grade ${valB.grade}`;

                log(desc);
                await sleep(600);

                if (cmp < 0) {
                    // Swap
                    [arr[j], arr[j-1]] = [arr[j-1], arr[j]];
                    setStudents([...arr]);
                    log("  -> Swap (Out of order)");
                    await sleep(400);
                } else {
                    log("  -> In order");
                    break;
                }
            }
        }

        setActivePair(null);
        setIsSorted(true);
        setIsRunning(false);
        log("Sort Complete.");
    };

    return (
        <div className="viz-container" style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <div>
                    <h3 style={{ margin: 0, color: 'var(--text-main)', fontSize: '1rem', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                        <Users size={16} />
                        Comparator Visualization
                    </h3>
                    <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>
                        Sorting Objects by different keys
                    </div>
                </div>
                <div style={{ display: 'flex', gap: '0.5rem' }}>
                    <button onClick={reset} disabled={isRunning} className="btn">
                        <RotateCcw size={14} /> Reset
                    </button>
                    <button onClick={runSort} disabled={isRunning || isSorted} className="btn btn-primary">
                        <Play size={14} /> Sort
                    </button>
                </div>
            </div>

            {/* Controls */}
            <div style={{ display: 'flex', gap: '1rem', background: 'var(--bg-sidebar)', padding: '0.5rem', borderRadius: '4px', border: '1px solid var(--border-color)' }}>
                <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: '0.25rem' }}>
                    <label style={{ fontSize: '0.75rem', fontWeight: 'bold' }}>Sort Key (Comparator)</label>
                    <div style={{ display: 'flex', gap: '0.5rem' }}>
                        <button 
                            onClick={() => { setSortBy('name'); reset(); }} 
                            className={`btn ${sortBy==='name'?'btn-primary':''}`}
                            disabled={isRunning}
                            style={{ flex: 1, fontSize: '0.75rem' }}
                        >
                            By Name
                        </button>
                        <button 
                            onClick={() => { setSortBy('section'); reset(); }} 
                            className={`btn ${sortBy==='section'?'btn-primary':''}`}
                            disabled={isRunning}
                            style={{ flex: 1, fontSize: '0.75rem' }}
                        >
                            By Section
                        </button>
                        <button 
                            onClick={() => { setSortBy('grade'); reset(); }} 
                            className={`btn ${sortBy==='grade'?'btn-primary':''}`}
                            disabled={isRunning}
                            style={{ flex: 1, fontSize: '0.75rem' }}
                        >
                            By Grade
                        </button>
                    </div>
                </div>
                <div style={{ width: '100px', display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'var(--bg-main)', borderRadius: '4px', border: '1px solid var(--border-color)' }}>
                    <div style={{ textAlign: 'center' }}>
                        <div style={{ fontSize: '0.6rem', textTransform: 'uppercase', color: 'var(--text-muted)' }}>Compares</div>
                        <div style={{ fontSize: '1.2rem', fontWeight: 'bold' }}>{compares}</div>
                    </div>
                </div>
            </div>

            {/* List View */}
            <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                <div style={{ display: 'grid', gridTemplateColumns: '40px 1fr 60px 60px', padding: '0.5rem', fontSize: '0.75rem', fontWeight: 'bold', color: 'var(--text-muted)', borderBottom: '1px solid var(--border-color)' }}>
                    <div>ID</div>
                    <div>Name</div>
                    <div>Sec</div>
                    <div>Grade</div>
                </div>
                {students.map((s, i) => {
                    const isActive = activePair && (activePair.includes(i));
                    const isFocus = sortBy === 'name' ? 'name' : (sortBy === 'section' ? 'section' : 'grade');

                    return (
                        <div 
                            key={s.id} 
                            style={{ 
                                display: 'grid', gridTemplateColumns: '40px 1fr 60px 60px', padding: '0.5rem', 
                                background: isActive ? 'var(--hover-bg)' : 'transparent',
                                border: isActive ? '1px solid var(--accent-color)' : '1px solid transparent',
                                borderRadius: '4px',
                                transition: 'all 0.2s',
                                fontSize: '0.85rem'
                            }}
                        >
                            <div style={{ opacity: 0.5 }}>{s.id}</div>
                            <div style={{ fontWeight: isFocus === 'name' ? 'bold' : 'normal', color: isFocus === 'name' ? 'var(--accent-color)' : 'inherit' }}>{s.name}</div>
                            <div style={{ fontWeight: isFocus === 'section' ? 'bold' : 'normal', color: isFocus === 'section' ? 'var(--accent-color)' : 'inherit' }}>{s.section}</div>
                            <div style={{ fontWeight: isFocus === 'grade' ? 'bold' : 'normal', color: isFocus === 'grade' ? 'var(--accent-color)' : 'inherit' }}>{s.grade}</div>
                        </div>
                    );
                })}
            </div>

            {/* Log */}
            <div style={{ height: '80px', padding: '0.5rem', background: '#0f172a', borderRadius: '4px', border: '1px solid var(--border-color)', overflowY: 'auto', fontFamily: 'monospace', fontSize: '0.75rem', display: 'flex', flexDirection: 'column-reverse' }}>
                {logs.map((l, i) => (
                    <div key={i} style={{ marginBottom: '2px', color: i === 0 ? '#fff' : '#64748b' }}>{l}</div>
                ))}
            </div>
        </div>
    );
};
]]></content>
