import React, { useState, useRef, useMemo } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import remarkMath from 'remark-math';
import rehypeRaw from 'rehype-raw';
import rehypeHighlight from 'rehype-highlight';
import { Edit3, Columns, Eye } from 'lucide-react';
import { MermaidDiagram } from './engines/MermaidDiagram';
import { SmilesDiagram } from './engines/SmilesDiagram';
import { InteractivePlot } from './engines/InteractivePlot';
import { PhysicsSimulation } from './engines/PhysicsSimulation';
import { SortingVisualizer } from './engines/SortingVisualizer';
import { NetworkConnectivity } from './engines/NetworkConnectivity';
import { ChemicalBalancer } from './engines/ChemicalBalancer';
import { PercolationVisualizer } from './engines/PercolationVisualizer';
import { SearchVisualizer } from './engines/SearchVisualizer';
import { MemoryVisualizer } from './engines/MemoryVisualizer';
import { StackVisualizer } from './engines/StackVisualizer';
import { QueueVisualizer } from './engines/QueueVisualizer';
import { IteratorVisualizer } from './engines/IteratorVisualizer';
import { TwoStackVisualizer } from './engines/TwoStackVisualizer';
import { MergeSortVisualizer } from './engines/MergeSortVisualizer';
import { ConvexHullVisualizer } from './engines/ConvexHullVisualizer';
import { ComparatorVisualizer } from './engines/ComparatorVisualizer';
import { EditorToolbar } from './editor/EditorToolbar';

interface EditorProps {
  content: string;
  fileName: string;
  onChange: (content: string) => void;
  readOnly?: boolean;
}

export const Editor: React.FC<EditorProps> = ({ content, fileName, onChange, readOnly = false }) => {
  const [view, setView] = useState<'split' | 'editor' | 'preview'>('split');
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  // Memoize markdown components to prevent re-mounting visualizers on every keystroke
  const markdownComponents = useMemo(() => ({
    a: ({node, ...props}: any) => <a {...props} target="_blank" rel="noopener noreferrer" />,
    code({node, inline, className, children, ...props}: any) {
        const match = /language-([\w-]+)/.exec(className || '');
        if (!inline) {
          switch (match?.[1]) {
            case 'mermaid': return <MermaidDiagram chart={String(children).replace(/\n$/, '')} />;
            case 'smiles': return <SmilesDiagram smiles={String(children).replace(/\n$/, '')} />;
            case 'plot': return <InteractivePlot configStr={String(children).replace(/\n$/, '')} />;
            case 'physics': return <PhysicsSimulation configStr={String(children).replace(/\n$/, '')} />;
            case 'sorting': return <SortingVisualizer configStr={String(children).replace(/\n$/, '')} />;
            case 'connectivity': return <NetworkConnectivity configStr={String(children).replace(/\n$/, '')} />;
            case 'chemical-reaction': return <ChemicalBalancer configStr={String(children).replace(/\n$/, '')} />;
            case 'percolation': return <PercolationVisualizer configStr={String(children).replace(/\n$/, '')} />;
            case 'search': return <SearchVisualizer configStr={String(children).replace(/\n$/, '')} />;
            case 'memory': return <MemoryVisualizer configStr={String(children).replace(/\n$/, '')} />;
            case 'stack': return <StackVisualizer configStr={String(children).replace(/\n$/, '')} />;
            case 'queue': return <QueueVisualizer configStr={String(children).replace(/\n$/, '')} />;
            case 'iterator': return <IteratorVisualizer configStr={String(children).replace(/\n$/, '')} />;
            case 'twostack': return <TwoStackVisualizer configStr={String(children).replace(/\n$/, '')} />;
            case 'mergesort': return <MergeSortVisualizer configStr={String(children).replace(/\n$/, '')} />;
            case 'convexhull': return <ConvexHullVisualizer configStr={String(children).replace(/\n$/, '')} />;
            case 'comparator': return <ComparatorVisualizer configStr={String(children).replace(/\n$/, '')} />;
          }
        }
        return <code className={className} {...props}>{children}</code>;
    },
    // @ts-ignore
    'model-viewer': ({node, ...props}: any) => <model-viewer {...props}></model-viewer>,
    div: ({node, className, ...props}: any) => className?.includes('math-display') ? <div dangerouslySetInnerHTML={{__html: window.katex?.renderToString(props['data-math'], {displayMode:true, throwOnError:false}) || ''}} {...props}/> : <div className={className} {...props}/>,
    span: ({node, className, ...props}: any) => className?.includes('math-inline') ? <span dangerouslySetInnerHTML={{__html: window.katex?.renderToString(props['data-math'], {displayMode:false, throwOnError:false}) || ''}} {...props}/> : <span className={className} {...props}/>
  }), []);

  const insertFormat = (prefix: string, suffix: string = '', blockMode: boolean = false) => {
    if (!textareaRef.current || readOnly) return;
    const { selectionStart: start, selectionEnd: end, value: text } = textareaRef.current;
    const selected = text.substring(start, end);
    let newText = '', newCursor = 0;

    if (blockMode) {
        const hasNewline = text.substring(0, start).endsWith('\n') || start === 0;
        newText = `${text.substring(0, start)}${hasNewline ? '' : '\n'}${prefix}${selected}${suffix}${text.substring(end)}`;
        newCursor = start + prefix.length + (hasNewline ? 0 : 1) + selected.length;
    } else {
        newText = `${text.substring(0, start)}${prefix}${selected}${suffix}${text.substring(end)}`;
        newCursor = start + prefix.length + selected.length;
    }
    onChange(newText);
    setTimeout(() => { textareaRef.current?.focus(); textareaRef.current?.setSelectionRange(newCursor, newCursor); }, 0);
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Tab') {
      e.preventDefault();
      const { selectionStart: start, selectionEnd: end, value } = e.currentTarget;
      onChange(value.substring(0, start) + '  ' + value.substring(end));
      setTimeout(() => { if(textareaRef.current) textareaRef.current.selectionStart = textareaRef.current.selectionEnd = start + 2; }, 0);
    }
  };

  return (
    <div className="editor-container bg-[var(--bg-main)] text-[var(--text-main)]">
      <div className="editor-header bg-[var(--bg-toolbar)] border-[var(--border-color)]">
        <div className="h-10 flex items-center justify-between px-4 border-b border-[var(--border-color)]">
             <div className="text-sm flex items-center gap-2"><span className="font-medium font-mono text-[var(--accent-color)]">{fileName}</span>{readOnly && <span className="text-xs px-2 py-0.5 rounded bg-[var(--bg-sidebar)] text-[var(--text-muted)]">Read Only</span>}</div>
            <div className="flex rounded p-0.5 bg-[var(--bg-main)]">
                {['editor', 'split', 'preview'].map((v: any) => (
                    <button key={v} onClick={() => setView(v)} className={`p-1.5 rounded transition-colors ${view===v ? 'bg-[var(--accent-color)] text-white' : 'text-[var(--text-muted)]'} ${v==='split'?'md-visible hidden':''}`}>
                        {v==='editor' ? <Edit3 size={14}/> : v==='split' ? <Columns size={14}/> : <Eye size={14}/>}
                    </button>
                ))}
            </div>
        </div>
        {(view !== 'preview' && !readOnly) && <EditorToolbar insertFormat={insertFormat} readOnly={readOnly} />}
      </div>
      <div className="split-container">
        {(view === 'split' || view === 'editor') && (
            <div className={`pane ${view === 'split' ? 'half border-r' : 'full'}`}>
                <textarea ref={textareaRef} className="textarea" value={content} onChange={e => onChange(e.target.value)} onKeyDown={handleKeyDown} placeholder="# Start typing..." spellCheck={false} disabled={readOnly} />
            </div>
        )}
        {(view === 'split' || view === 'preview') && (
            <div id="markdown-preview" className={`pane ${view === 'split' ? 'half' : 'full'} preview-area`}>
                <div className="markdown-body">
                    <ReactMarkdown 
                        remarkPlugins={[remarkGfm, remarkMath]} 
                        rehypePlugins={[rehypeRaw, rehypeHighlight]}
                        components={markdownComponents}
                        remarkRehypeOptions={{ handlers: { math: (s:any, n:any) => ({ type: 'element', tagName: 'div', properties: { className: ['math-display'], 'data-math': n.value }, children: [] }), inlineMath: (s:any, n:any) => ({ type: 'element', tagName: 'span', properties: { className: ['math-inline'], 'data-math': n.value }, children: [] }) }}}
                    >{content}</ReactMarkdown>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};
]]></content>
