import { 
  Bold, Italic, Strikethrough, 
  Heading1, Heading2, Heading3, 
  List, ListOrdered, CheckSquare, 
  Quote, Code, Link, Image, Table, Minus,
  Sigma, Workflow, Hexagon, Activity, Atom, 
  BarChart3, GitMerge, Search, Network, Droplet, 
  Cpu, Layers, AlignLeft, Repeat, Calculator, Crosshair, FlaskConical,
  Box, Terminal, Users
} from 'lucide-react';
import { 
  PLOT_TEMPLATE, PHYSICS_TEMPLATE, SORTING_TEMPLATE, 
  CONNECTIVITY_TEMPLATE, PERCOLATION_TEMPLATE, REACTION_TEMPLATE, 
  SEARCH_TEMPLATE, MEMORY_TEMPLATE, STACK_TEMPLATE, 
  QUEUE_TEMPLATE, ITERATOR_TEMPLATE, TWOSTACK_TEMPLATE, 
  MERGE_TEMPLATE, CONVEX_TEMPLATE, COMPARATOR_TEMPLATE
} from './templates';

type TabName = 'Write' | 'Insert' | 'Math/Sci' | 'Algorithms' | 'Data Structs';

export const EditorToolbar = ({ insertFormat, readOnly }: { insertFormat: (p: string, s?: string, b?: boolean) => void, readOnly?: boolean }) => {
  const [activeTab, setActiveTab] = useState<TabName>('Write');

  if (readOnly) return null;

  const ToolbarButton = ({ icon: Icon, title, action, color }: { icon: any, title: string, action: () => void, color?: string }) => (
    <button 
      onClick={action} 
      className="btn-icon" 
      title={title} 
      style={{ color: color, padding: '0.5rem', margin: '0 1px' }}
    >
      <Icon size={18} />
    </button>
  );

  const Group = ({ children, label }: { children: React.ReactNode, label?: string }) => (
    <div style={{ display: 'flex', alignItems: 'center', gap: '2px', padding: '0 8px', borderRight: '1px solid var(--border-color)', position: 'relative' }}>
      {children}
      {label && <span style={{ position: 'absolute', bottom: '-2px', left: 0, right: 0, textAlign: 'center', fontSize: '8px', color: 'var(--text-muted)', textTransform: 'uppercase', pointerEvents: 'none' }}>{label}</span>}
    </div>
