import React, { useRef, useEffect, useState } from 'react';
import mermaid from 'mermaid';
import { Maximize2, Minimize2, ZoomIn, ZoomOut, RefreshCw, Move } from 'lucide-react';

export const MermaidDiagram = ({ chart }: { chart: string }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const svgWrapperRef = useRef<HTMLDivElement>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [transform, setTransform] = useState({ x: 0, y: 0, scale: 1 });
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });

  useEffect(() => {
    let isMounted = true;

    const renderDiagram = async () => {
      if (!svgWrapperRef.current) return;
      try {
        mermaid.initialize({ 
          startOnLoad: false, 
          theme: 'dark', 
          securityLevel: 'loose',
          fontFamily: 'inherit' 
        });

        await new Promise(resolve => requestAnimationFrame(resolve));
        if (!isMounted) return;

        const id = `mermaid-${Math.random().toString(36).substr(2, 9)}`;
        const { svg } = await mermaid.render(id, chart);

        if (isMounted && svgWrapperRef.current) {
            svgWrapperRef.current.innerHTML = svg;
            const svgEl = svgWrapperRef.current.querySelector('svg');
            if (svgEl) {
                svgEl.style.width = '100%';
                svgEl.style.height = 'auto';
                svgEl.style.maxWidth = '100%';
                svgEl.style.display = 'block';
            }
            // Reset transform when new chart renders
            setTransform({ x: 0, y: 0, scale: 1 });
        }
      } catch (err) {
        if (isMounted && svgWrapperRef.current) {
            console.error("Mermaid error:", err);
            svgWrapperRef.current.innerHTML = `<div style="color:#f87171;font-size:0.75rem;padding:0.5rem;border:1px solid rgba(239,68,68,0.5);border-radius:0.25rem;background:rgba(127,29,29,0.1);font-family:monospace;white-space:pre-wrap">Syntax Error:\n${(err as Error).message}</div>`;
        }
      }
    };
    renderDiagram();
    return () => { isMounted = false; };
  }, [chart]);

  const handleZoom = (delta: number) => {
    setTransform(prev => ({
      ...prev,
      scale: Math.max(0.1, Math.min(5, prev.scale + delta))
    }));
  };

  const handleWheel = (e: React.WheelEvent) => {
    if (e.ctrlKey || e.metaKey) {
        e.preventDefault();
        handleZoom(e.deltaY > 0 ? -0.1 : 0.1);
    }
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    setIsDragging(true);
    setDragStart({ x: e.clientX - transform.x, y: e.clientY - transform.y });
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDragging) return;
    setTransform(prev => ({
      ...prev,
      x: e.clientX - dragStart.x,
      y: e.clientY - dragStart.y
    }));
  };

  const handleMouseUp = () => setIsDragging(false);

  const toggleFullscreen = () => {
    setIsFullscreen(!isFullscreen);
    setTransform({ x: 0, y: 0, scale: 1 });
  };

  const resetView = () => setTransform({ x: 0, y: 0, scale: 1 });

  const containerStyle: React.CSSProperties = isFullscreen ? {
    position: 'fixed',
    inset: 0,
    zIndex: 9999,
    backgroundColor: 'var(--bg-main)',
    display: 'flex',
    flexDirection: 'column',
    padding: '2rem'
  } : {
    position: 'relative',
    minHeight: '300px',
    backgroundColor: 'var(--bg-sidebar)',
    borderRadius: '0.5rem',
    border: '1px solid var(--border-color)',
    margin: '1.5rem 0',
    overflow: 'hidden'
  };

  return (
    <div 
        ref={containerRef} 
        style={containerStyle}
        onWheel={handleWheel}
        className="mermaid-interactive-container"
    >
      {/* Controls Overlay */}
      <div style={{ 
          position: 'absolute', 
          top: '0.75rem', 
          right: '0.75rem', 
          display: 'flex', 
          gap: '0.5rem', 
          zIndex: 10,
          backgroundColor: 'rgba(0,0,0,0.4)',
          padding: '0.25rem',
          borderRadius: '0.5rem',
          backdropFilter: 'blur(4px)'
      }}>
        <button onClick={() => handleZoom(0.1)} className="btn-icon" title="Zoom In"><ZoomIn size={16}/></button>
        <button onClick={() => handleZoom(-0.1)} className="btn-icon" title="Zoom Out"><ZoomOut size={16}/></button>
        <button onClick={resetView} className="btn-icon" title="Reset View"><RefreshCw size={16}/></button>
        <div style={{ width: '1px', backgroundColor: 'rgba(255,255,255,0.2)', margin: '0 0.25rem' }} />
        <button onClick={toggleFullscreen} className="btn-icon" title={isFullscreen ? "Exit Fullscreen" : "Fullscreen"}>
          {isFullscreen ? <Minimize2 size={16}/> : <Maximize2 size={16}/>}
        </button>
      </div>

      {/* Movement Hint */}
      {!isFullscreen && (
          <div style={{ 
              position: 'absolute', 
              bottom: '0.5rem', 
              left: '0.5rem', 
              fontSize: '10px', 
              color: 'var(--text-muted)', 
              display: 'flex', 
              alignItems: 'center', 
              gap: '4px',
              pointerEvents: 'none'
          }}>
              <Move size={12}/> Drag to pan • Ctrl+Scroll to zoom
          </div>
      )}

      <div 
        style={{ 
            flex: 1, 
            cursor: isDragging ? 'grabbing' : 'grab',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            overflow: 'hidden'
        }}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onMouseLeave={handleMouseUp}
      >
        <div 
          ref={svgWrapperRef}
          style={{ 
              transform: `translate(${transform.x}px, ${transform.y}px) scale(${transform.scale})`,
              transition: isDragging ? 'none' : 'transform 0.1s ease-out',
              transformOrigin: 'center center',
              width: isFullscreen ? 'auto' : '100%',
              maxWidth: isFullscreen ? 'none' : '100%',
              display: 'flex',
              justifyContent: 'center'
          }}
        />
      </div>
    </div>
  );
};

