interface EditorProps {
  content: string;
  fileName: string;
  onChange: (content: string) => void;
  readOnly?: boolean;
}

export const Editor: React.FC<EditorProps> = ({ content, fileName, onChange, readOnly = false }) => {
  const [view, setView] = useState<'split' | 'editor' | 'preview'>('split');
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  const markdownComponents = useMemo(() => ({
    a: ({node, ...props}: any) => <a {...props} target="_blank" rel="noopener noreferrer" />,
    code({node, inline, className, children, ...props}: any) {
        const match = /language-([\w-]+)/.exec(className || '');
        if (!inline) {
          switch (match?.[1]) {
            case 'mermaid': return <MermaidDiagram chart={String(children).replace(/\n$/, '')} />;
            case 'smiles': return <SmilesDiagram smiles={String(children).replace(/\n$/, '')} />;
            case 'plot': return <InteractivePlot configStr={String(children).replace(/\n$/, '')} />;
            case 'physics': return <PhysicsSimulation configStr={String(children).replace(/\n$/, '')} />;
            case 'sorting': return <SortingVisualizer configStr={String(children).replace(/\n$/, '')} />;
            case 'connectivity': return <NetworkConnectivity configStr={String(children).replace(/\n$/, '')} />;
            case 'chemical-reaction': return <ChemicalBalancer configStr={String(children).replace(/\n$/, '')} />;
            case 'percolation': return <PercolationVisualizer configStr={String(children).replace(/\n$/, '')} />;
            case 'search': return <SearchVisualizer configStr={String(children).replace(/\n$/, '')} />;
            case 'memory': return <MemoryVisualizer configStr={String(children).replace(/\n$/, '')} />;
            case 'stack': return <StackVisualizer configStr={String(children).replace(/\n$/, '')} />;
            case 'queue': return <QueueVisualizer configStr={String(children).replace(/\n$/, '')} />;
            case 'iterator': return <IteratorVisualizer configStr={String(children).replace(/\n$/, '')} />;
            case 'twostack': return <TwoStackVisualizer configStr={String(children).replace(/\n$/, '')} />;
            case 'mergesort': return <MergeSortVisualizer configStr={String(children).replace(/\n$/, '')} />;
            case 'convexhull': return <ConvexHullVisualizer configStr={String(children).replace(/\n$/, '')} />;
            case 'comparator': return <ComparatorVisualizer configStr={String(children).replace(/\n$/, '')} />;
          }
        }
        return <code className={className} {...props}>{children}</code>;
    },
    // Fix for model-viewer custom element
    'model-viewer': (props: any) => {
      const { node, ...rest } = props;
      return React.createElement('model-viewer', { ...rest });
    },
    div: ({node, className, ...props}: any) => className?.includes('math-display') ? <div dangerouslySetInnerHTML={{__html: window.katex?.renderToString(props['data-math'], {displayMode:true, throwOnError:false}) || ''}} {...props}/> : <div className={className} {...props}/>,
    span: ({node, className, ...props}: any) => className?.includes('math-inline') ? <span dangerouslySetInnerHTML={{__html: window.katex?.renderToString(props['data-math'], {displayMode:false, throwOnError:false}) || ''}} {...props}/> : <span className={className} {...props}/>
  }), []);

  const insertFormat = (prefix: string, suffix: string = '', blockMode: boolean = false) => {
    if (!textareaRef.current || readOnly) return;
    const { selectionStart: start, selectionEnd: end, value: text } = textareaRef.current;
    const selected = text.substring(start, end);
    let newText = '', newCursor = 0;

    if (blockMode) {
        const hasNewline = text.substring(0, start).endsWith('\n') || start === 0;
        newText = `${text.substring(0, start)}${hasNewline ? '' : '\n'}${prefix}${selected}${suffix}${text.substring(end)}`;
        newCursor = start + prefix.length + (hasNewline ? 0 : 1) + selected.length;
    } else {
        newText = `${text.substring(0, start)}${prefix}${selected}${suffix}${text.substring(end)}`;
        newCursor = start + prefix.length + selected.length;
    }
    onChange(newText);
    setTimeout(() => { textareaRef.current?.focus(); textareaRef.current?.setSelectionRange(newCursor, newCursor); }, 0);
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Tab') {
      e.preventDefault();
      const { selectionStart: start, selectionEnd: end, value } = e.currentTarget;
      onChange(value.substring(0, start) + '  ' + value.substring(end));
      setTimeout(() => { if(textareaRef.current) textareaRef.current.selectionStart = textareaRef.current.selectionEnd = start + 2; }, 0);
    }
  };

  return (
    <div className="flex flex-col h-full bg-[var(--bg-main)] text-[var(--text-main)]">
      <div className="border-b bg-[var(--bg-toolbar)] border-[var(--border-color)]">
        <div className="h-10 flex items-center justify-between px-4 border-b border-[var(--border-color)]">
             <div className="text-sm flex items-center gap-2"><span className="font-medium font-mono text-[var(--accent-color)]">{fileName}</span>{readOnly && <span className="text-xs px-2 py-0.5 rounded bg-[var(--bg-sidebar)] text-[var(--text-muted)]">Read Only</span>}</div>
            <div className="flex rounded p-0.5 bg-[var(--bg-main)]">
                {['editor', 'split', 'preview'].map((v: any) => (
                    <button key={v} onClick={() => setView(v)} className={`p-1.5 rounded transition-colors ${view===v ? 'bg-[var(--accent-color)] text-white' : 'text-[var(--text-muted)]'} ${v==='split'?'hidden md:block':''}`}>
                        {v==='editor' ? <Edit3 size={14}/> : v==='split' ? <Columns size={14}/> : <Eye size={14}/>}
                    </button>
                ))}
            </div>
        </div>
        {(view !== 'preview' && !readOnly) && <EditorToolbar insertFormat={insertFormat} readOnly={readOnly} />}
      </div>
      <div className="flex-1 flex overflow-hidden">
        {(view === 'split' || view === 'editor') && (
            <div className={`h-full flex flex-col ${view === 'split' ? 'w-1/2 border-r' : 'w-full'} border-[var(--border-color)]`}>
                <textarea ref={textareaRef} className="w-full h-full p-4 resize-none focus:outline-none font-mono text-sm leading-relaxed bg-[var(--bg-main)] text-[var(--text-main)]" value={content} onChange={e => onChange(e.target.value)} onKeyDown={handleKeyDown} placeholder="# Start typing..." spellCheck={false} disabled={readOnly} />
            </div>
        )}
        {(view === 'split' || view === 'preview') && (
            <div id="markdown-preview" className={`h-full overflow-y-auto p-8 ${view === 'split' ? 'w-1/2' : 'w-full'} bg-[var(--bg-main)]`}>
                <div className="markdown-body max-w-4xl mx-auto">
                    <ReactMarkdown 
                        remarkPlugins={[remarkGfm, remarkMath]} 
                        rehypePlugins={[rehypeRaw, rehypeHighlight]}
                        components={markdownComponents as any}
                        remarkRehypeOptions={{ handlers: { math: (s:any, n:any) => ({ type: 'element', tagName: 'div', properties: { className: ['math-display'], 'data-math': n.value }, children: [] }), inlineMath: (s:any, n:any) => ({ type: 'element', tagName: 'span', properties: { className: ['math-inline'], 'data-math': n.value }, children: [] }) }}}
                    >{content}</ReactMarkdown>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import mermaid from 'mermaid';
import { Maximize2, Minimize2, ZoomIn, ZoomOut, RefreshCw, Move } from 'lucide-react';

export const MermaidDiagram = ({ chart }: { chart: string }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const svgWrapperRef = useRef<HTMLDivElement>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [transform, setTransform] = useState({ x: 0, y: 0, scale: 1 });
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });

  useEffect(() => {
    let isMounted = true;

    const renderDiagram = async () => {
      if (!svgWrapperRef.current) return;
      try {
        mermaid.initialize({ 
          startOnLoad: false, 
          theme: 'dark', 
          securityLevel: 'loose',
          fontFamily: 'inherit' 
        });

        await new Promise(resolve => requestAnimationFrame(resolve));
        if (!isMounted) return;

        const id = `mermaid-${Math.random().toString(36).substr(2, 9)}`;
        const { svg } = await mermaid.render(id, chart);

        if (isMounted && svgWrapperRef.current) {
            svgWrapperRef.current.innerHTML = svg;
            const svgEl = svgWrapperRef.current.querySelector('svg');
            if (svgEl) {
                svgEl.style.width = '100%';
                svgEl.style.height = 'auto';
                svgEl.style.maxWidth = '100%';
                svgEl.style.display = 'block';
                svgEl.style.pointerEvents = 'none'; // Let the wrapper handle interaction
            }
            setTransform({ x: 0, y: 0, scale: 1 });
        }
      } catch (err) {
        if (isMounted && svgWrapperRef.current) {
            console.error("Mermaid error:", err);
            svgWrapperRef.current.innerHTML = `<div style="color:#f87171;font-size:0.75rem;padding:0.5rem;border:1px solid rgba(239,68,68,0.5);border-radius:0.25rem;background:rgba(127,29,29,0.1);font-family:monospace;white-space:pre-wrap">Syntax Error:\n${(err as Error).message}</div>`;
        }
      }
    };
    renderDiagram();
    return () => { isMounted = false; };
  }, [chart]);

  const handleZoom = (delta: number) => {
    setTransform(prev => ({
      ...prev,
      scale: Math.max(0.1, Math.min(10, prev.scale + delta))
    }));
  };

  const handleWheel = (e: React.WheelEvent) => {
    if (e.ctrlKey || e.metaKey) {
        e.preventDefault();
        handleZoom(e.deltaY > 0 ? -0.1 : 0.1);
    }
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    setIsDragging(true);
    setDragStart({ x: e.clientX - transform.x, y: e.clientY - transform.y });
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDragging) return;
    setTransform(prev => ({
      ...prev,
      x: e.clientX - dragStart.x,
      y: e.clientY - dragStart.y
    }));
  };

  const handleMouseUp = () => setIsDragging(false);

  const toggleFullscreen = () => {
    setIsFullscreen(!isFullscreen);
    setTransform({ x: 0, y: 0, scale: 1 });
  };

  const resetView = () => setTransform({ x: 0, y: 0, scale: 1 });

  const containerStyle: React.CSSProperties = isFullscreen ? {
    position: 'fixed',
    inset: 0,
    zIndex: 9999,
    backgroundColor: 'var(--bg-main)',
    display: 'flex',
    flexDirection: 'column',
    padding: '2rem'
  } : {
    position: 'relative',
    minHeight: '300px',
    backgroundColor: 'var(--bg-sidebar)',
    borderRadius: '0.5rem',
    border: '1px solid var(--border-color)',
    margin: '1.5rem 0',
    overflow: 'hidden'
  };

  return (
    <div 
        ref={containerRef} 
        style={containerStyle}
        onWheel={handleWheel}
        className="mermaid-interactive-container group"
    >
      {/* Controls Overlay */}
      <div style={{ 
          position: 'absolute', 
          top: '0.75rem', 
          right: '0.75rem', 
          display: 'flex', 
          gap: '0.5rem', 
          zIndex: 10,
          backgroundColor: 'rgba(0,0,0,0.6)',
          padding: '0.35rem',
          borderRadius: '0.5rem',
          backdropFilter: 'blur(8px)',
          border: '1px solid rgba(255,255,255,0.1)'
      }}>
        <button onClick={() => handleZoom(0.2)} className="btn-icon hover:bg-white/10" title="Zoom In"><ZoomIn size={16}/></button>
        <button onClick={() => handleZoom(-0.2)} className="btn-icon hover:bg-white/10" title="Zoom Out"><ZoomOut size={16}/></button>
        <button onClick={resetView} className="btn-icon hover:bg-white/10" title="Reset View"><RefreshCw size={16}/></button>
        <div style={{ width: '1px', backgroundColor: 'rgba(255,255,255,0.2)', margin: '0 0.25rem' }} />
        <button onClick={toggleFullscreen} className="btn-icon hover:bg-white/10" title={isFullscreen ? "Exit Fullscreen" : "Fullscreen"}>
          {isFullscreen ? <Minimize2 size={16}/> : <Maximize2 size={16}/>}
        </button>
      </div>

      {/* Movement Hint */}
      {!isFullscreen && (
          <div className="opacity-0 group-hover:opacity-100 transition-opacity duration-300" style={{ 
              position: 'absolute', 
              bottom: '0.5rem', 
              left: '0.5rem', 
              fontSize: '10px', 
              color: 'var(--text-muted)', 
              display: 'flex', 
              alignItems: 'center', 
              gap: '4px',
              pointerEvents: 'none',
              backgroundColor: 'rgba(0,0,0,0.4)',
              padding: '2px 6px',
              borderRadius: '4px'
          }}>
              <Move size={12}/> Drag to pan • Ctrl+Scroll to zoom
          </div>
      )}

      <div 
        style={{ 
            flex: 1, 
            cursor: isDragging ? 'grabbing' : 'grab',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            overflow: 'hidden'
        }}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onMouseLeave={handleMouseUp}
      >
        <div 
          ref={svgWrapperRef}
          style={{ 
              transform: `translate(${transform.x}px, ${transform.y}px) scale(${transform.scale})`,
              transition: isDragging ? 'none' : 'transform 0.15s ease-out',
              transformOrigin: 'center center',
              width: '100%',
              display: 'flex',
              justifyContent: 'center'
          }}
        />
      </div>
    </div>
  );
};

